$regPath = "HKLM:\SYSTEM\CurrentControlSet\Control\Print\Monitors"

$findings = @()
$actions  = @()
$success  = $true

Write-Host ""
Write-Host "=== print-monitors ===" -ForegroundColor Cyan

try {
    if (-not (Test-Path -Path $regPath)) {
        Write-Host "  [OK] Print Monitors key not found" -ForegroundColor Green
    } else {
        $subkeys = @(Get-ChildItem -Path $regPath -ErrorAction Stop)
        foreach ($subkey in $subkeys) {
            $monitorName = $subkey.PSChildName
            if ($allowedMonitors -contains $monitorName) {
                Write-Host "  [OK] '$monitorName' whitelisted" -ForegroundColor Green
            } else {
                $findings += "Unknown Print Monitor: '$monitorName'"
                Write-Host "  [FIND] Unknown Print Monitor: '$monitorName'" -ForegroundColor Red
                try {
                    Remove-Item -Path $subkey.PSPath -Recurse -Force -ErrorAction Stop
                    $actions += "Print Monitor '$monitorName' removed"
                    Write-Host "  [OK] '$monitorName' removed" -ForegroundColor Green
                } catch {
                    $actions += "Failed to remove '$monitorName': $_"
                    Write-Host "  [WARN] Error removing '$monitorName': $_" -ForegroundColor Yellow
                    $success = $false
                }
            }
        }
    }
} catch {
    Write-Host "  [WARN] Error checking Print Monitors: $_" -ForegroundColor Yellow
    $success = $false
}

Write-Host ""

[PSCustomObject]@{
    Module   = "print-monitors"
    Findings = $findings
    Actions  = $actions
    Success  = $success
}

# === MODULE: profile_defend.ps1 ===
#Requires -RunAsAdministrator

$suspiciousPattern = 'cmd|powershell|shell|exec|download|iex|invoke|rundll'

$profiles = @(
    $PROFILE,
    $PROFILE.AllUsersCurrentHost,
    $PROFILE.CurrentUserAllHosts,
    $PROFILE.AllUsersAllHosts,
    "$PSHOME\profile.ps1"
)

$findings = @()
$actions  = @()
$success  = $true

Write-Host ""
Write-Host "=== profile-injection ===" -ForegroundColor Cyan

foreach ($prof in $profiles) {
    try {
        if (-not (Test-Path -LiteralPath $prof -ErrorAction SilentlyContinue)) {
            Write-Host "  [OK] Not found: $prof" -ForegroundColor Green
            continue
        }
        $lines = Get-Content -LiteralPath $prof -ErrorAction Stop
        $hits  = @($lines | Where-Object { $_ -match $suspiciousPattern })
        if ($hits.Count -eq 0) {
            Write-Host "  [OK] Clean: $prof" -ForegroundColor Green
        } else {
            $findings += "Suspicious profile: '$prof' ($($hits.Count) matching lines)"
            Write-Host "  [FIND] Suspicious content in: $prof" -ForegroundColor Red
            foreach ($h in $hits) { Write-Host "    > $h" -ForegroundColor Red }
            try {
                Remove-Item -LiteralPath $prof -Force -ErrorAction Stop
                $actions += "Profile removed: '$prof'"
                Write-Host "  [OK] Profile removed: $prof" -ForegroundColor Green
            } catch {
                $actions += "Failed to remove profile '$prof': $_"
                Write-Host "  [WARN] Error removing '$prof': $_" -ForegroundColor Yellow
                $success = $false
            }
        }
    } catch {
        Write-Host "  [WARN] Error checking '$prof': $_" -ForegroundColor Yellow
        $success = $false
    }
}

Write-Host ""

[PSCustomObject]@{
    Module   = "profile-injection"
    Findings = $findings
    Actions  = $actions
    Success  = $success
}

