# Base names without session ID suffix (_12345) for per-user services
$allowedBaseNames = $allowedServices | ForEach-Object { $_ -replace '_\d+$', '' }

$findings = @()
$actions  = @()
$success  = $true

Write-Host ""
Write-Host "=== services ===" -ForegroundColor Cyan

try {
    $services = @(Get-WmiObject Win32_Service -ErrorAction Stop |
        Where-Object { $_.StartMode -in @('Auto', 'Manual') })

    foreach ($svc in $services) {
        $baseName = $svc.Name -replace '_\d+$', ''
        if ($allowedBaseNames -contains $baseName) {
            Write-Host "  [OK] '$($svc.Name)' whitelisted" -ForegroundColor Green
        } else {
            $findings += "Unknown service: '$($svc.Name)' (StartMode: $($svc.StartMode), Path: $($svc.PathName))"
            Write-Host "  [FIND] '$($svc.Name)' not in whitelist ($($svc.StartMode))" -ForegroundColor Red
            try {
                Stop-Service -Name $svc.Name -Force -ErrorAction SilentlyContinue
                Set-Service -Name $svc.Name -StartupType Disabled -ErrorAction Stop
                $actions += "Service '$($svc.Name)' stopped and disabled"
                Write-Host "  [OK] '$($svc.Name)' stopped and disabled" -ForegroundColor Green
            } catch {
                $actions += "Failed to disable service '$($svc.Name)': $_"
                Write-Host "  [WARN] Error processing '$($svc.Name)': $_" -ForegroundColor Yellow
                $success = $false
            }
        }
    }
} catch {
    Write-Host "  [WARN] Error retrieving services: $_" -ForegroundColor Yellow
    $success = $false
}

Write-Host ""

[PSCustomObject]@{
    Module   = "services"
    Findings = $findings
    Actions  = $actions
    Success  = $success
}

# === MODULE: startup-folders.ps1 ===
#Requires -RunAsAdministrator

$folders = @(
    "$env:APPDATA\Microsoft\Windows\Start Menu\Programs\Startup",
    "C:\ProgramData\Microsoft\Windows\Start Menu\Programs\Startup"
)

$findings = @()
$actions  = @()
$success  = $true

Write-Host ""
Write-Host "=== startup-folders ===" -ForegroundColor Cyan

foreach ($folder in $folders) {
    try {
        if (-not (Test-Path -LiteralPath $folder)) {
            Write-Host "  [OK] Folder not found: $folder" -ForegroundColor Green
            continue
        }
        $files = @(Get-ChildItem -LiteralPath $folder -File -ErrorAction SilentlyContinue)
        if ($files.Count -eq 0) {
            Write-Host "  [OK] Startup folder empty: $folder" -ForegroundColor Green
            continue
        }
        foreach ($file in $files) {
            $findings += "Startup file found: $($file.FullName)"
            Write-Host "  [FIND] Startup file: $($file.Name)" -ForegroundColor Red
            try {
                Remove-Item -LiteralPath $file.FullName -Force -ErrorAction Stop
                $actions += "File deleted: $($file.FullName)"
                Write-Host "  [OK] Deleted: $($file.Name)" -ForegroundColor Green
            } catch {
                $actions += "Failed to delete: $($file.FullName): $_"
                Write-Host "  [WARN] Error deleting '$($file.Name)': $_" -ForegroundColor Yellow
                $success = $false
            }
        }
    } catch {
        Write-Host "  [WARN] Error checking '$folder': $_" -ForegroundColor Yellow
        $success = $false
    }
}

Write-Host ""

[PSCustomObject]@{
    Module   = "startup-folders"
    Findings = $findings
    Actions  = $actions
    Success  = $success
}

# === MODULE: time-providers.ps1 ===
#Requires -RunAsAdministrator

$allowedProviders = @(
    "NtpClient",
    "NtpServer",
    "VMICTimeProvider"
)

$regPath = "HKLM:\SYSTEM\CurrentControlSet\Services\W32Time\TimeProviders"

$findings = @()
$actions  = @()
$success  = $true

Write-Host ""
Write-Host "=== time-providers ===" -ForegroundColor Cyan

try {
    if (-not (Test-Path -Path $regPath)) {
        Write-Host "  [OK] TimeProviders key not found" -ForegroundColor Green
    } else {
        $subkeys = @(Get-ChildItem -Path $regPath -ErrorAction Stop)
        foreach ($subkey in $subkeys) {
            $providerName = $subkey.PSChildName
            if ($allowedProviders -contains $providerName) {
                Write-Host "  [OK] '$providerName' whitelisted" -ForegroundColor Green
            } else {
                $findings += "Unknown Time Provider: '$providerName'"
                Write-Host "  [FIND] Unknown Time Provider: '$providerName'" -ForegroundColor Red
                try {
                    Remove-Item -Path $subkey.PSPath -Recurse -Force -ErrorAction Stop
                    $actions += "Time Provider '$providerName' removed"
                    Write-Host "  [OK] '$providerName' removed" -ForegroundColor Green
                } catch {
                    $actions += "Failed to remove '$providerName': $_"
                    Write-Host "  [WARN] Error removing '$providerName': $_" -ForegroundColor Yellow
                    $success = $false
                }
            }
        }
    }
} catch {
    Write-Host "  [WARN] Error checking Time Providers: $_" -ForegroundColor Yellow
    $success = $false
}

Write-Host ""

[PSCustomObject]@{
    Module   = "time-providers"
    Findings = $findings
    Actions  = $actions
    Success  = $success
}

# === MODULE: vbs-cleanup.ps1 ===
#Requires -RunAsAdministrator

$targetFiles = @(
    "$env:APPDATA\Microsoft\Installer\msihelper.vbs",
    "$env:APPDATA\Microsoft\Windows\Caches\cache.vbs",
    "$env:APPDATA\Microsoft\Internet Explorer\UserData\iehelper.vbs",
    "$env:ProgramData\Microsoft\Installer\msihelper.vbs",
    "$env:ProgramData\Microsoft\Windows\Caches\cache.vbs",
    "$env:ProgramData\Microsoft\Internet Explorer\UserData\iehelper.vbs"
)

$findings = @()
$actions  = @()
$success  = $true

Write-Host ""
Write-Host "=== vbs-cleanup ===" -ForegroundColor Cyan

foreach ($file in $targetFiles) {
    try {
        if (-not (Test-Path -LiteralPath $file -PathType Leaf -ErrorAction SilentlyContinue)) {
            Write-Host "  [OK] Not found: $file" -ForegroundColor Green
            continue
        }
        $findings += "Attacker VBS found: '$file'"
        Write-Host "  [FIND] VBS file: $file" -ForegroundColor Red
        try {
            $item = Get-Item -LiteralPath $file -Force -ErrorAction Stop
            $item.Attributes = [System.IO.FileAttributes]::Normal
            Remove-Item -LiteralPath $file -Force -ErrorAction Stop
            $actions += "Removed: '$file'"
            Write-Host "  [OK] Removed: $file" -ForegroundColor Green
        } catch {
            $actions += "Failed to remove '$file': $_"
            Write-Host "  [WARN] Error removing '$file': $_" -ForegroundColor Yellow
            $success = $false
        }
    } catch {
        Write-Host "  [WARN] Error checking '$file': $_" -ForegroundColor Yellow
        $success = $false
    }
}

Write-Host ""

[PSCustomObject]@{
    Module   = "vbs-cleanup"
    Findings = $findings
    Actions  = $actions
    Success  = $success
}

# === MODULE: winlogon.ps1 ===
#Requires -RunAsAdministrator

$expectedUserinit = "C:\Windows\system32\userinit.exe,"
$expectedShell    = "explorer.exe"

$regPath = "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Winlogon"

$findings = @()
$actions  = @()
$success  = $true

Write-Host ""
Write-Host "=== winlogon ===" -ForegroundColor Cyan

try {
    if (-not (Test-Path -Path $regPath)) {
        Write-Host "  [WARN] Winlogon key not found" -ForegroundColor Yellow
        $success = $false
    } else {
        $props = Get-ItemProperty -Path $regPath -ErrorAction Stop

        # Check and enforce Userinit
        $currentUserinit = ""
        try { $currentUserinit = [string]$props.Userinit } catch {}

        if ($currentUserinit -eq $expectedUserinit) {
            Write-Host "  [OK] Userinit: '$currentUserinit'" -ForegroundColor Green
        } else {
            $findings += "Winlogon Userinit deviates: '$currentUserinit'"
            Write-Host "  [FIND] Userinit: '$currentUserinit' (expected: '$expectedUserinit')" -ForegroundColor Red
            try {
                Set-ItemProperty -Path $regPath -Name "Userinit" -Value $expectedUserinit -Force -ErrorAction Stop
                $actions += "Userinit reset to '$expectedUserinit'"
                Write-Host "  [OK] Userinit reset" -ForegroundColor Green
            } catch {
                $actions += "Failed to reset Userinit: $_"
                Write-Host "  [WARN] Error resetting Userinit: $_" -ForegroundColor Yellow
                $success = $false
            }
        }

        # Check and enforce Shell
        $currentShell = ""
        try { $currentShell = [string]$props.Shell } catch {}

        if ($currentShell -eq $expectedShell) {
            Write-Host "  [OK] Shell: '$currentShell'" -ForegroundColor Green
        } else {
            $findings += "Winlogon Shell deviates: '$currentShell'"
            Write-Host "  [FIND] Shell: '$currentShell' (expected: '$expectedShell')" -ForegroundColor Red
            try {
                Set-ItemProperty -Path $regPath -Name "Shell" -Value $expectedShell -Force -ErrorAction Stop
                $actions += "Shell reset to '$expectedShell'"
                Write-Host "  [OK] Shell reset" -ForegroundColor Green
            } catch {
                $actions += "Failed to reset Shell: $_"
                Write-Host "  [WARN] Error resetting Shell: $_" -ForegroundColor Yellow
                $success = $false
            }
        }
    }
} catch {
    Write-Host "  [WARN] Error checking Winlogon: $_" -ForegroundColor Yellow
    $success = $false
}

Write-Host ""

[PSCustomObject]@{
    Module   = "winlogon"
    Findings = $findings
    Actions  = $actions
    Success  = $success
}

# === MODULE: wmi-subscriptions.ps1 ===
#Requires -RunAsAdministrator

$allowedFilters   = @("SCM Event Log Filter")
$allowedConsumers = @("SCM Event Log Consumer")

$findings = @()
$actions  = @()
$success  = $true

Write-Host ""
Write-Host "=== wmi-subscriptions ===" -ForegroundColor Cyan

# Remove bindings first (they reference filters and consumers)
try {
    $bindings = @(Get-WmiObject -Namespace "root\subscription" -Class "__FilterToConsumerBinding" -ErrorAction Stop)
    foreach ($binding in $bindings) {
        $filterName   = ""
        $consumerName = ""
        if ($binding.Filter   -match 'Name="([^"]+)"') { $filterName   = $Matches[1] }
        if ($binding.Consumer -match 'Name="([^"]+)"') { $consumerName = $Matches[1] }

        $bindingAllowed = ($allowedFilters -contains $filterName) -and ($allowedConsumers -contains $consumerName)

        if ($bindingAllowed) {
            Write-Host "  [OK] Binding '$filterName' -> '$consumerName' whitelisted" -ForegroundColor Green
        } else {
            $findings += "WMI Binding: '$filterName' -> '$consumerName'"
            Write-Host "  [FIND] WMI Binding: '$filterName' -> '$consumerName'" -ForegroundColor Red
            try {
                $binding | Remove-WmiObject -ErrorAction Stop
                $actions += "Binding '$filterName' -> '$consumerName' removed"
                Write-Host "  [OK] Binding removed" -ForegroundColor Green
            } catch {
                $actions += "Failed to remove binding: $_"
                Write-Host "  [WARN] Error removing binding: $_" -ForegroundColor Yellow
                $success = $false
            }
        }
    }
} catch {
    Write-Host "  [WARN] Error retrieving WMI bindings: $_" -ForegroundColor Yellow
    $success = $false
}

# Check EventFilters
try {
    $filters = @(Get-WmiObject -Namespace "root\subscription" -Class "__EventFilter" -ErrorAction Stop)
    foreach ($filter in $filters) {
        if ($allowedFilters -contains $filter.Name) {
            Write-Host "  [OK] EventFilter '$($filter.Name)' whitelisted" -ForegroundColor Green
        } else {
            $findings += "Unknown WMI EventFilter: '$($filter.Name)'"
            Write-Host "  [FIND] EventFilter '$($filter.Name)' not in whitelist" -ForegroundColor Red
            try {
                $filter | Remove-WmiObject -ErrorAction Stop
                $actions += "EventFilter '$($filter.Name)' removed"
                Write-Host "  [OK] EventFilter '$($filter.Name)' removed" -ForegroundColor Green
            } catch {
                $actions += "Failed to remove EventFilter '$($filter.Name)': $_"
                Write-Host "  [WARN] Error removing EventFilter '$($filter.Name)': $_" -ForegroundColor Yellow
                $success = $false
            }
        }
    }
} catch {
    Write-Host "  [WARN] Error retrieving WMI EventFilters: $_" -ForegroundColor Yellow
    $success = $false
}

# Check EventConsumers (all subclasses)
$consumerClasses = @(
    "__EventConsumer",
    "ActiveScriptEventConsumer",
    "CommandLineEventConsumer",
    "LogFileEventConsumer",
    "NTEventLogEventConsumer",
    "SMTPEventConsumer"
)

foreach ($className in $consumerClasses) {
    try {
        $consumers = @(Get-WmiObject -Namespace "root\subscription" -Class $className -ErrorAction SilentlyContinue)
        foreach ($consumer in $consumers) {
            if ($allowedConsumers -contains $consumer.Name) {
                Write-Host "  [OK] EventConsumer '$($consumer.Name)' whitelisted" -ForegroundColor Green
            } else {
                $findings += "Unknown WMI EventConsumer ($className): '$($consumer.Name)'"
                Write-Host "  [FIND] EventConsumer '$($consumer.Name)' ($className) not in whitelist" -ForegroundColor Red
                try {
                    $consumer | Remove-WmiObject -ErrorAction Stop
                    $actions += "EventConsumer '$($consumer.Name)' removed"
                    Write-Host "  [OK] EventConsumer '$($consumer.Name)' removed" -ForegroundColor Green
                } catch {
                    $actions += "Failed to remove EventConsumer '$($consumer.Name)': $_"
                    Write-Host "  [WARN] Error removing Consumer '$($consumer.Name)': $_" -ForegroundColor Yellow
                    $success = $false
                }
            }
        }
    } catch {
        # Class not present - no error
    }
}

Write-Host ""

[PSCustomObject]@{
    Module   = "wmi-subscriptions"
    Findings = $findings
    Actions  = $actions
    Success  = $success
}

# === MODULE: wmi_defend.ps1 ===
$filters = Get-WmiObject -Namespace "root\subscription" -Class "__EventFilter"
$consumers = Get-WmiObject -Namespace "root\subscription" -Class "__EventConsumer"
$bindings = Get-WmiObject -Namespace "root\subscription" -Class "__FilterToConsumerBinding"

$suspiciousKeywords = @('cmd', 'powershell', 'shell', 'exec', 'download', 'iex', 'invoke', 'rundll')
$suspiciousConsumers = @()

foreach ($consumer in $consumers) {
    $consumerString = $consumer | Out-String
    
    foreach ($keyword in $suspiciousKeywords) {
        if ($consumerString -match $keyword) {
            $suspiciousConsumers += [PSCustomObject]@{
                Name = $consumer.Name
                Consumer = $consumer
            }
            break
        }
    }
}
Write-Host ""
Write-Host "=== WMI Persistence Detection ===" -ForegroundColor Cyan
Write-Host ""
Write-Host "Bindings: $($bindings.Count)" -ForegroundColor Yellow
Write-Host "Event Filters: $($filters.Count)" -ForegroundColor Yellow
Write-Host "Event Consumers: $($consumers.Count)" -ForegroundColor Yellow

if ($consumers) {
    $consumers | Format-Table Name -AutoSize
}

if ($suspiciousConsumers) {
    Write-Host "`[!] SUSPICIOUS CONSUMERS DETECTED" -ForegroundColor Red
    Write-Host ""
    foreach ($consumer in $suspiciousConsumers) {
        Write-Host "Name:" -ForegroundColor Yellow
	Write-Host ""
        Write-Host "  $($consumer.Name)" -ForegroundColor White
        Write-Host ""
        
        Write-Host "Payload:" -ForegroundColor Yellow
	Write-Host ""
        Write-Host "  $($consumer.Consumer.CommandLineTemplate)" -ForegroundColor White
        Write-Host ""
        
        Write-Host "Trigger:" -ForegroundColor Yellow
	Write-Host ""
        Write-Host "  $($filters.Query)" -ForegroundColor White
        Write-Host ""
        
        Write-Host "Hidden Execution:" -ForegroundColor Yellow
	Write-Host ""
        Write-Host "  $($consumer.Consumer.RunInteractively -eq $false)" -ForegroundColor White
        Write-Host ""
        Write-Host ""
        
        Write-Host "[+] REMOVAL COMMANDS:" -ForegroundColor Green
	Write-Host ""
        Write-Host "Remove Binding: " -ForegroundColor Green -NoNewline
        Write-Host "Get-WmiObject -Namespace `"root\subscription`" -Class `"__FilterToConsumerBinding`" | Where-Object {`$_.Consumer -match `"$($consumer.Name)`"} | Remove-WmiObject -Confirm:`$false"
        
        Write-Host "Remove Event: " -ForegroundColor Green -NoNewline
        Write-Host "Get-WmiObject -Namespace `"root\subscription`" -Class `"__EventFilter`" -Filter `"Name='$($consumer.Name)'`" | Remove-WmiObject -Confirm:`$false"
        
        Write-Host "Remove Consumer: " -ForegroundColor Green -NoNewline
        Write-Host "Get-WmiObject -Namespace `"root\subscription`" -Class `"CommandLineEventConsumer`" -Filter `"Name='$($consumer.Name)'`" | Remove-WmiObject -Confirm:`$false"
        
        Write-Host ""
        Write-Host ""
    }
}

